#!/usr/bin/env bash
# Baseline smoke test for harness-companion.mjs sprint cycle.
# Generated by the initializer agent -- edit to match your project.
set -e

PROJECT_ROOT="$(cd "$(dirname "$0")/.." && pwd)"
SCRIPTS_DIR="$PROJECT_ROOT/plugins/harness/scripts"

# Verify Node.js is available
if command -v node > /dev/null 2>&1; then
  NODE_VERSION=$(node --version)
  echo "OK -- Node.js available ($NODE_VERSION)"
else
  echo "FAIL -- Node.js not found in PATH"
  exit 1
fi

# Verify target scripts directory location is valid
# (the directory itself will be created during Sprint 1)
if [ -d "$PROJECT_ROOT/plugins/harness" ]; then
  echo "OK -- plugins/harness/ exists (scripts/ will be created here)"
else
  echo "FAIL -- plugins/harness/ directory not found"
  exit 1
fi

# Verify evaluator role file exists (F-011 target)
if [ -f "$PROJECT_ROOT/plugins/harness/skills/harness/roles/evaluator.md" ]; then
  echo "OK -- evaluator.md exists (F-011 target)"
else
  echo "FAIL -- evaluator.md not found"
  exit 1
fi

# Verify harness state files exist
if [ -f "$PROJECT_ROOT/.harness/features.json" ] && [ -f "$PROJECT_ROOT/.harness/state.json" ]; then
  echo "OK -- harness state files present"
else
  echo "FAIL -- harness state files missing"
  exit 1
fi

echo "Baseline verified. Ready for sprint."
